  1→//! Automatic mock generation for external dependencies.
  2→//!
  3→//! Classifies external dependencies into categories (I/O, library, utility)
  4→//! and generates sensible default [`MockConfig`]s without requiring user
  5→//! configuration. Users can override defaults via `.shatter/config.yaml`.
  6→
  7→use std::collections::HashMap;
  8→
  9→use serde_json::{json, Value};
 10→
 11→use crate::protocol::{ExternalDependency, MockBehavior, MockConfig};
 12→use crate::scope::{DependencyAction, ScopeMatcher};
 13→use crate::types::TypeInfo;
 14→
 15→/// Category of an external dependency, used to select default mock behavior.
 16→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 17→pub enum IoCategory {
 18→    /// File system operations (fs, path).
 19→    FileSystem,
 20→    /// Network operations (http, fetch, axios, net).
 21→    Network,
 22→    /// Database operations (pg, mysql, mongodb, redis, prisma, knex).
 23→    Database,
 24→    /// Pure utility functions (lodash, ramda, date-fns) — safe to call.
 25→    PureUtility,
 26→    /// Other external library — use type-aware stub.
 27→    ExternalOther,
 28→}
 29→
 30→/// Known module prefixes for each category.
 31→const FS_MODULES: &[&str] = &[
 32→    "fs", "node:fs", "fs/promises", "node:fs/promises", "path", "node:path",
 33→    // Go stdlib
 34→    "os", "io", "io/ioutil", "bufio",
 35→];
 36→const NETWORK_MODULES: &[&str] = &[
 37→    "http", "https", "node:http", "node:https", "net", "node:net",
 38→    "axios", "node-fetch", "fetch", "got", "superagent", "request",
 39→    "undici",
 40→];
 41→const DB_MODULES: &[&str] = &[
 42→    "pg", "mysql", "mysql2", "mongodb", "redis", "ioredis",
 43→    "prisma", "@prisma/client", "knex", "sequelize", "typeorm",
 44→    "mongoose", "sqlite3", "better-sqlite3", "drizzle-orm",
 45→    "database/sql", "gorm.io/gorm",
 46→];
 47→const PURE_UTILITY_MODULES: &[&str] = &[
 48→    "lodash", "lodash-es", "underscore", "ramda", "date-fns",
 49→    "dayjs", "moment", "validator", "uuid", "nanoid",
 50→    "chalk", "debug", "ms",
 51→    "strings", "strconv", "fmt", "math", "sort",
 52→];
 53→
 54→/// Classify an external dependency into an [`IoCategory`].
 55→pub fn classify_dependency(dep: &ExternalDependency) -> IoCategory {
 56→    let module = dep.source_module.as_str();
 57→
 58→    if FS_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 59→        return IoCategory::FileSystem;
 60→    }
 61→    if NETWORK_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 62→        return IoCategory::Network;
 63→    }
 64→    if DB_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 65→        return IoCategory::Database;
 66→    }
 67→    if PURE_UTILITY_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 68→        return IoCategory::PureUtility;
 69→    }
 70→
 71→    IoCategory::ExternalOther
 72→}
 73→
 74→/// Generate a default [`MockConfig`] for a dependency based on its category.
 75→pub fn generate_default_mock(dep: &ExternalDependency, category: IoCategory) -> MockConfig {
 76→    match category {
 77→        IoCategory::FileSystem => MockConfig {
 78→            symbol: dep.symbol.clone(),
 79→            return_values: vec![default_for_fs(&dep.symbol)],
 80→            should_track_calls: true,
 81→            default_behavior: MockBehavior::RepeatLast,
 82→        },
 83→        IoCategory::Network => MockConfig {
 84→            symbol: dep.symbol.clone(),
 85→            return_values: vec![json!({"status": 200, "data": {}})],
 86→            should_track_calls: true,
 87→            default_behavior: MockBehavior::RepeatLast,
 88→        },
 89→        IoCategory::Database => MockConfig {
 90→            symbol: dep.symbol.clone(),
 91→            return_values: vec![default_for_db(&dep.symbol)],
 92→            should_track_calls: true,
 93→            default_behavior: MockBehavior::RepeatLast,
 94→        },
 95→        IoCategory::PureUtility => MockConfig {
 96→            symbol: dep.symbol.clone(),
 97→            return_values: vec![],
 98→            should_track_calls: false,
 99→            default_behavior: MockBehavior::Passthrough,
100→        },
101→        IoCategory::ExternalOther => MockConfig {
102→            symbol: dep.symbol.clone(),
103→            return_values: vec![default_for_type(&dep.return_type)],
104→            should_track_calls: true,
105→            default_behavior: MockBehavior::RepeatLast,
106→        },
107→    }
108→}
109→
110→/// Pick a sensible default for a file-system operation based on the symbol name.
111→fn default_for_fs(symbol: &str) -> Value {
112→    let lower = symbol.to_lowercase();
113→    if lower.contains("read") {
114→        json!("")
115→    } else if lower.contains("stat") || lower.contains("lstat") {
116→        json!({"size": 0, "isFile": true, "isDirectory": false})
117→    } else if lower.contains("exists") {
118→        json!(true)
119→    } else if lower.contains("readdir") || lower.contains("glob") {
120→        json!([])
121→    } else {
122→        // write, mkdir, unlink, etc. — return undefined/null (success)
123→        Value::Null
124→    }
125→}
126→
127→/// Pick a sensible default for a database operation based on the symbol name.
128→fn default_for_db(symbol: &str) -> Value {
129→    let lower = symbol.to_lowercase();
130→    if lower.contains("query") || lower.contains("find") || lower.contains("select") || lower.contains("all") {
131→        json!({"rows": []})
132→    } else if lower.contains("insert") || lower.contains("create") || lower.contains("save") {
133→        json!({"rowCount": 1})
134→    } else if lower.contains("update") || lower.contains("delete") || lower.contains("remove") {
135→        json!({"rowCount": 0})
136→    } else {
137→        Value::Null
138→    }
139→}
140→
141→/// Generate a type-appropriate default value from TypeInfo.
142→fn default_for_type(typ: &TypeInfo) -> Value {
143→    match typ {
144→        TypeInfo::Int => json!(0),
145→        TypeInfo::Float => json!(0.0),
146→        TypeInfo::Str => json!(""),
147→        TypeInfo::Bool => json!(false),
148→        TypeInfo::Array { .. } => json!([]),
149→        TypeInfo::Object { fields } => {
150→            let mut obj = serde_json::Map::new();
151→            for (name, field_type) in fields {
152→                obj.insert(name.clone(), default_for_type(field_type));
153→            }
154→            Value::Object(obj)
155→        }
156→        TypeInfo::Nullable { .. } => Value::Null,
157→        TypeInfo::Union { variants } => {
158→            if let Some(first) = variants.first() {
159→                default_for_type(first)
160→            } else {
161→                Value::Null
162→            }
163→        }
164→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Value::Null,
165→    }
166→}
