127→impl ObserveState {
128→    pub fn new() -> Self {
129→        Self {
130→            seen_paths: HashSet::new(),
131→            seen_branch_ids: HashSet::new(),
132→            all_lines: HashSet::new(),
133→        }
134→    }
135→}
