143→/// Result of observing a single input execution, classified against caller-owned
144→/// tracking state.
145→#[derive(Debug)]
146→pub struct SingleObservation {
147→    /// The raw execution result from the frontend.
148→    pub exec_result: ExecuteResult,
149→    /// Hash of this execution's path (scope-aware when available).
150→    pub path_hash: u64,
151→    /// Whether this path hash was new (not previously in `seen_paths`).
152→    pub is_new_path: bool,
153→    /// Branch IDs discovered for the first time in this execution.
154→    pub new_branch_ids: Vec<u32>,
155→    /// Execution summary, present only when `is_new_path` is true.
156→    pub execution_summary: Option<ExecutionSummary>,
157→}
158→
159→/// Execute a single input and classify the result against caller-owned tracking
160→/// state.
161→///
162→/// This is the canonical execution primitive — the single source of truth for
163→/// the execute → parse → hash → track cycle. Both [`observe_batch`] and
164→/// [`explorer::explore_function`](crate::explorer::explore_function) route
165→/// through this function.
166→///
167→/// The caller provides mutable references to its coverage sets; this function
168→/// updates them in place and returns the classified observation.
169→pub async fn observe_single(
170→    frontend: &mut Frontend,
171→    function_name: &str,
172→    inputs: &[serde_json::Value],
173→    mocks: &[MockConfig],
174→    setup_context: Option<&SetupContextStack>,
175→    loop_buckets: &LoopBuckets,
176→    state: &mut ObserveState,
177→) -> Result<SingleObservation, ObserveError> {
178→    let response = frontend
179→        .send(ProtoCommand::Execute {
180→            function: function_name.to_string(),
181→            inputs: inputs.to_vec(),
182→            mocks: mocks.to_vec(),
183→            setup_context: setup_context.cloned(),
184→        })
185→        .await?;
186→
187→    let exec_result = match response.result {
188→        ResponseResult::Execute(result) => *result,
189→        ResponseResult::Error { code, message, .. } => {
190→            return Err(ObserveError::UnexpectedResponse(format!(
191→                "execute error ({code:?}): {message}"
192→            )));
193→        }
194→        other => {
195→            return Err(ObserveError::UnexpectedResponse(format!(
196→                "expected Execute response, got {other:?}"
197→            )));
198→        }
199→    };
200→
201→    for &line in &exec_result.lines_executed {
202→        state.all_lines.insert(line);
203→    }
204→
205→    let hash = path_hash(&exec_result, loop_buckets);
206→    let is_new_path = state.seen_paths.insert(hash);
207→
208→    let mut new_branch_ids = Vec::new();
209→    for decision in &exec_result.branch_path {
210→        if state.seen_branch_ids.insert(decision.branch_id) {
211→            new_branch_ids.push(decision.branch_id);
212→        }
213→    }
214→
215→    let execution_summary = if is_new_path {
216→        let error_intent = classify_error_intent(&exec_result);
217→        Some(ExecutionSummary {
218→            inputs: inputs.to_vec(),
219→            return_value: exec_result.return_value.clone(),
220→            thrown_error: exec_result
221→                .thrown_error
222→                .as_ref()
223→                .map(|e| format!("{}: {}", e.error_type, e.message)),
224→            lines_executed: exec_result.lines_executed.clone(),
225→            is_new_path: true,
226→            error_intent,
227→        })
228→    } else {
229→        None
230→    };
231→
232→    Ok(SingleObservation {
233→        exec_result,
234→        path_hash: hash,
235→        is_new_path,
236→        new_branch_ids,
237→        execution_summary,
238→    })
239→}
240→
241→/// Execute a batch of inputs against an already-instrumented function.
242→///
243→/// Routes each input through [`observe_single`], the canonical execution
244→/// primitive. No instrumentation, no setup/teardown lifecycle — the caller
245→/// manages those concerns.
246→///
247→/// Each input vector is executed sequentially. Returns raw execution data,
248→/// path hashes, line coverage, and discovery attribution.
249→pub async fn observe_batch(
250→    frontend: &mut Frontend,
251→    function_name: &str,
252→    inputs: Vec<Vec<serde_json::Value>>,
253→    mocks: &[MockConfig],
254→    setup_context: Option<&SetupContextStack>,
255→    loop_buckets: &LoopBuckets,
256→    timeout: Option<Duration>,
257→) -> Result<BatchObservation, ObserveError> {
258→    let mut state = ObserveState::new();
259→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
260→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
261→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
262→
263→    let start = Instant::now();
264→
265→    for input in inputs {
266→        if timeout.is_some_and(|t| start.elapsed() >= t) {
267→            break;
268→        }
269→
270→        let obs = observe_single(
271→            frontend,
272→            function_name,
273→            &input,
274→            mocks,
275→            setup_context,
276→            loop_buckets,
277→            &mut state,
278→        )
279→        .await?;
280→
281→        for branch_id in &obs.new_branch_ids {
282→            discoveries.push((*branch_id, DiscoveryMethod::Random));
283→        }
284→        if let Some(summary) = obs.execution_summary {
285→            new_path_executions.push(summary);
286→        }
287→
288→        raw_results.push((input, mocks.to_vec(), obs.exec_result));
289→    }
290→
291→    Ok(BatchObservation {
292→        raw_results,
293→        unique_path_hashes: state.seen_paths,
294→        lines_covered: state.all_lines,
295→        discoveries,
296→        new_path_executions,
297→    })
298→}
299→
300→/// Execute a function with pre-generated inputs and collect execution traces.
301→///
302→/// Handles the full observation lifecycle: instrument → setup → execute batch →
303→/// teardown. Returns `ObservationOutput` compatible with the rest of the pipeline.
304→///
305→/// Callers supply pre-generated inputs (random, boundary, user-provided). This
306→/// function does not generate inputs — that separation keeps the observe stage
307→/// composable and testable.
308→pub async fn observe_function(
309→    frontend: &mut Frontend,
310→    analysis: &FunctionAnalysis,
311→    inputs: Vec<Vec<serde_json::Value>>,
312→    config: &ObserveConfig,
313→) -> Result<ObservationOutput, ObserveError> {
314→    let total_input_count = inputs.len() as u32;
315→
316→    // --- Instrumentation ---
317→    let instrumentable_line_count = if config.skip_instrument {
318→        None
319→    } else {
320→        let instrument_response = frontend
321→            .send(ProtoCommand::Instrument {
322→                file: config.file.clone(),
323→                function: analysis.name.clone(),
324→                mocks: config.mocks.clone(),
325→                project_root: config.project_root.clone(),
326→            })
327→            .await?;
328→
329→        match instrument_response.result {
330→            ResponseResult::Instrument {
331→                instrumented,
332→                instrumentable_line_count,
333→                ..
334→            } => {
335→                if !instrumented {
336→                    return Err(ObserveError::InstrumentationFailed(
337→                        "instrumentation returned instrumented=false".to_string(),
338→                    ));
339→                }
340→                instrumentable_line_count
341→            }
342→            ResponseResult::Error { code, message, .. } => {
343→                return Err(ObserveError::InstrumentationFailed(format!(
344→                    "instrument error ({code:?}): {message}"
345→                )));
346→            }
347→            other => {
348→                return Err(ObserveError::UnexpectedResponse(format!(
349→                    "expected Instrument response, got {other:?}"
350→                )));
351→            }
352→        }
353→    };
354→
355→    // --- Setup lifecycle ---
356→    let has_setup =
357→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
358→    let per_function_setup = has_setup && config.setup_level == SetupLevel::Function;
359→    let per_execution_setup = has_setup && config.setup_level == SetupLevel::Execution;
360→
361→    let mut setup_context: Option<SetupContextStack> = None;
362→
363→    if per_function_setup
364→        && let Some(ref setup_file) = config.setup_file
365→    {
366→        setup_context = send_setup(
367→            frontend,
368→            setup_file,
369→            &analysis.name,
370→            config.setup_level,
371→            config.project_root.clone(),
372→        )
373→        .await?;
374→    }
375→
376→    // --- Execute batch ---
377→    // For per-execution setup, we need to interleave setup/teardown with each execution.
378→    let batch = if per_execution_setup {
379→        observe_batch_with_per_execution_setup(
380→            frontend,
381→            analysis,
382→            inputs,
383→            config,
384→        )
385→        .await?
386→    } else {
387→        observe_batch(
388→            frontend,
389→            &analysis.name,
390→            inputs,
391→            &config.mocks,
392→            setup_context.as_ref(),
393→            &config.loop_buckets,
394→            config.timeout,
395→        )
396→        .await?
397→    };
398→
399→    // --- Per-function teardown ---
400→    if per_function_setup && frontend_supports(&config.capabilities, "teardown") {
401→        send_teardown(frontend, &analysis.name, config.setup_level).await?;
402→    }
403→
404→    let total_lines = instrumentable_line_count
405→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
406→
407→    Ok(ObservationOutput {
408→        function_name: analysis.name.clone(),
409→        iterations: total_input_count,
410→        unique_paths: batch.unique_path_hashes.len(),
411→        lines_covered: batch.lines_covered.len(),
412→        total_lines,
413→        new_path_executions: batch.new_path_executions,
414→        raw_results: batch.raw_results,
415→        discoveries: batch.discoveries,
416→        nondeterministic_fields: vec![],
417→        float_probe_results: vec![],
418→    })
419→}
420→
421→/// Execute inputs with per-execution setup/teardown interleaved.
422→async fn observe_batch_with_per_execution_setup(
423→    frontend: &mut Frontend,
424→    analysis: &FunctionAnalysis,
425→    inputs: Vec<Vec<serde_json::Value>>,
426→    config: &ObserveConfig,
427→) -> Result<BatchObservation, ObserveError> {
428→    let mut state = ObserveState::new();
429→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
430→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
431→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
432→
433→    let start = Instant::now();
434→
435→    for input in inputs {
436→        if config.timeout.is_some_and(|t| start.elapsed() >= t) {
437→            break;
438→        }
439→
440→        // Per-execution setup
441→        let setup_context = if let Some(ref setup_file) = config.setup_file {
442→            send_setup(
443→                frontend,
444→                setup_file,
445→                &analysis.name,
446→                config.setup_level,
447→                config.project_root.clone(),
448→            )
449→            .await?
450→        } else {
451→            None
452→        };
453→
454→        let obs = observe_single(
455→            frontend,
456→            &analysis.name,
457→            &input,
458→            &config.mocks,
459→            setup_context.as_ref(),
460→            &config.loop_buckets,
461→            &mut state,
462→        )
463→        .await?;
464→
465→        // Per-execution teardown
466→        if frontend_supports(&config.capabilities, "teardown") {
467→            send_teardown(frontend, &analysis.name, config.setup_level).await?;
468→        }
469→
470→        for branch_id in &obs.new_branch_ids {
471→            discoveries.push((*branch_id, DiscoveryMethod::Random));
472→        }
473→        if let Some(summary) = obs.execution_summary {
474→            new_path_executions.push(summary);
475→        }
476→
477→        raw_results.push((input, config.mocks.clone(), obs.exec_result));
478→    }
479→
480→    Ok(BatchObservation {
481→        raw_results,
482→        unique_path_hashes: state.seen_paths,
483→        lines_covered: state.all_lines,
484→        discoveries,
485→        new_path_executions,
486→    })
487→}
