//! Mock value space selection and live-first execution logic.
//!
//! When exploring a function that depends on external services, the mock value
//! space determines where return values come from. The live-first strategy
//! attempts a real call first, then classifies the result to decide whether
//! to continue using live values or fall back to autonomous mocking.

use serde::{Deserialize, Serialize};

use crate::execution_record::ErrorInfo;

// ---------------------------------------------------------------------------
// Connection failure heuristic patterns
// ---------------------------------------------------------------------------

/// Substrings in error messages that indicate a connection refused error.
pub const CONNECTION_REFUSED_PATTERNS: &[&str] = &[
    "ECONNREFUSED",
    "connection refused",
    "Connection refused",
];

/// Substrings in error messages that indicate a DNS resolution failure.
pub const DNS_FAILURE_PATTERNS: &[&str] = &[
    "ENOTFOUND",
    "EAI_AGAIN",
    "getaddrinfo",
    "dns resolution failed",
    "name or service not known",
    "Name or service not known",
];

/// Substrings in error messages that indicate an authentication/authorization error.
pub const AUTH_ERROR_PATTERNS: &[&str] = &[
    "401",
    "403",
    "Unauthorized",
    "unauthorized",
    "Forbidden",
    "forbidden",
    "authentication failed",
    "Authentication failed",
    "invalid credentials",
    "Invalid credentials",
    "access denied",
    "Access denied",
];

/// Substrings in error messages that indicate a timeout.
pub const TIMEOUT_PATTERNS: &[&str] = &[
    "ETIMEDOUT",
    "ESOCKETTIMEDOUT",
    "ECONNABORTED",
    "timeout",
    "Timeout",
    "timed out",
    "Timed out",
    "request timeout",
    "connect timeout",
];

/// Error types that typically indicate infrastructure-level failures.
pub const INFRA_ERROR_TYPES: &[&str] = &[
    "FetchError",
    "NetworkError",
    "AxiosError",
    "ConnectionError",
    "TimeoutError",
    "DNSError",
];

// ---------------------------------------------------------------------------
// MockValueSpace enum
// ---------------------------------------------------------------------------

/// Strategy for selecting mock return values during exploration.
///
/// Ordered from most realistic to most synthetic. The orchestrator picks a
/// strategy per dependency based on availability probing and user config.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Attempt a live call first; record the result for the behavior map.
    /// Falls back to [`Autonomous`](MockValueSpace::Autonomous) on connection failure.
    LiveFirst,
    /// Use a fixed set of return values provided by the user or behavior map.
    FixedSet,
    /// Generate plausible return values autonomously from type info and heuristics.
    Autonomous,
    /// Use seed values (from prior runs or user-provided examples) as the starting
    /// point, mutating them for coverage.
    Seeded,
}

// ---------------------------------------------------------------------------
// Live-first classification
// ---------------------------------------------------------------------------

/// Outcome of classifying a live call attempt.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum LiveCallOutcome {
    /// The call succeeded -- record the return value for the behavior map.
    Success,
    /// The dependency is unavailable (connection failure, DNS, timeout, auth).
    /// The orchestrator should switch to autonomous mocking.
    Unavailable(UnavailableReason),
    /// The call produced an application-level error (e.g. validation error,
    /// business logic exception). This is normal behavior, not unavailability.
    AppError,
}

/// Why a dependency was classified as unavailable.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum UnavailableReason {
    ConnectionRefused,
    DnsFailure,
    AuthFailure,
    Timeout,
    InfraError,
}

impl std::fmt::Display for UnavailableReason {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::ConnectionRefused => write!(f, "connection refused"),
            Self::DnsFailure => write!(f, "DNS resolution failed"),
            Self::AuthFailure => write!(f, "authentication/authorization failed"),
            Self::Timeout => write!(f, "connection timed out"),
            Self::InfraError => write!(f, "infrastructure error"),
        }
    }
}

/// Classify an execution result from a live dependency call.
///
/// Returns [`LiveCallOutcome::Success`] when the call completed without error
/// (even if the return value is null/empty -- that is valid service behavior).
/// Returns [`LiveCallOutcome::Unavailable`] when the error matches
/// connection failure heuristics. Everything else is [`LiveCallOutcome::AppError`].
pub fn classify_live_call(
    _return_value: Option<&serde_json::Value>,
    thrown_error: Option<&ErrorInfo>,
) -> LiveCallOutcome {
    // If there is no error, the call succeeded (even with no return value / void).
    let error = match thrown_error {
        Some(e) => e,
        None => return LiveCallOutcome::Success,
    };

    // We have an error -- check if it indicates infrastructure unavailability.
    if let Some(reason) = classify_connection_failure(error) {
        return LiveCallOutcome::Unavailable(reason);
    }

    LiveCallOutcome::AppError
}

/// Check whether an error indicates a connection/infrastructure failure.
///
/// Checks the error type name against known infrastructure error types,
/// then checks the error message against pattern lists for connection refused,
/// DNS failure, auth errors, and timeouts. Returns the first matching reason.
pub fn classify_connection_failure(error: &ErrorInfo) -> Option<UnavailableReason> {
    // Check error type first (more specific signal).
    if INFRA_ERROR_TYPES.iter().any(|t| error.error_type.contains(t)) {
        // Narrow down by message if possible.
        if let Some(reason) = classify_message(&error.message) {
            return Some(reason);
        }
        return Some(UnavailableReason::InfraError);
    }

    // Check error_category if the frontend classified it.
    if error.error_category.as_deref() == Some("infrastructure") {
        if let Some(reason) = classify_message(&error.message) {
            return Some(reason);
        }
        return Some(UnavailableReason::InfraError);
    }

    // Fall back to message pattern matching.
    classify_message(&error.message)
}

/// Classify an error message against known connection failure patterns.
fn classify_message(message: &str) -> Option<UnavailableReason> {
    if CONNECTION_REFUSED_PATTERNS.iter().any(|p| message.contains(p)) {
        return Some(UnavailableReason::ConnectionRefused);
    }
    if DNS_FAILURE_PATTERNS.iter().any(|p| message.contains(p)) {
        return Some(UnavailableReason::DnsFailure);
    }
    if TIMEOUT_PATTERNS.iter().any(|p| message.contains(p)) {
        return Some(UnavailableReason::Timeout);
    }
    if AUTH_ERROR_PATTERNS.iter().any(|p| message.contains(p)) {
        return Some(UnavailableReason::AuthFailure);
    }
    None
}

