        assert_eq!(UnavailableReason::DnsFailure.to_string(), "DNS resolution failed");
        assert_eq!(
            UnavailableReason::AuthFailure.to_string(),
            "authentication/authorization failed"
        );
        assert_eq!(UnavailableReason::Timeout.to_string(), "connection timed out");
        assert_eq!(UnavailableReason::InfraError.to_string(), "infrastructure error");
    }

    // --- UnavailableReason serde roundtrip ---

    #[test]
    fn unavailable_reason_serde_roundtrip() {
        let variants = [
            UnavailableReason::ConnectionRefused,
            UnavailableReason::DnsFailure,
            UnavailableReason::AuthFailure,
            UnavailableReason::Timeout,
            UnavailableReason::InfraError,
        ];
        for variant in &variants {
            let json = serde_json::to_string(variant).expect("serialize");
            let deserialized: UnavailableReason =
                serde_json::from_str(&json).expect("deserialize");
            assert_eq!(*variant, deserialized);
        }
    }

    // --- Edge cases ---

    #[test]
    fn error_with_return_value_is_still_classified() {
        // When both a return value and error are present, the error takes precedence.
        let error = make_error("Error", "ECONNREFUSED");
        let result = classify_live_call(Some(&json!({"partial": true})), Some(&error));
        assert_eq!(
            result,
            LiveCallOutcome::Unavailable(UnavailableReason::ConnectionRefused)
        );
    }

    #[test]
    fn empty_error_message_is_app_error() {
        let error = make_error("Error", "");
        let result = classify_live_call(None, Some(&error));
        assert_eq!(result, LiveCallOutcome::AppError);
    }

    #[test]
    fn no_match_returns_none() {
        let error = make_error("Error", "some normal error message");
        assert!(classify_connection_failure(&error).is_none());
    }
}

#[cfg(test)]
mod proptests {
    use super::*;
    use proptest::prelude::*;

    fn arb_mock_value_space() -> impl Strategy<Value = MockValueSpace> {
        prop_oneof![
            Just(MockValueSpace::LiveFirst),
            Just(MockValueSpace::FixedSet),
            Just(MockValueSpace::Autonomous),
            Just(MockValueSpace::Seeded),
        ]
    }

    fn arb_unavailable_reason() -> impl Strategy<Value = UnavailableReason> {
        prop_oneof![
            Just(UnavailableReason::ConnectionRefused),
            Just(UnavailableReason::DnsFailure),
            Just(UnavailableReason::AuthFailure),
            Just(UnavailableReason::Timeout),
            Just(UnavailableReason::InfraError),
        ]
    }

    fn arb_connection_failure_message() -> impl Strategy<Value = (String, UnavailableReason)> {
        prop_oneof![
            prop::sample::select(CONNECTION_REFUSED_PATTERNS)
                .prop_map(|p| (p.to_string(), UnavailableReason::ConnectionRefused)),
            prop::sample::select(DNS_FAILURE_PATTERNS)
                .prop_map(|p| (p.to_string(), UnavailableReason::DnsFailure)),
            prop::sample::select(TIMEOUT_PATTERNS)
                .prop_map(|p| (p.to_string(), UnavailableReason::Timeout)),
            prop::sample::select(AUTH_ERROR_PATTERNS)
                .prop_map(|p| (p.to_string(), UnavailableReason::AuthFailure)),
        ]
    }

    proptest! {
        /// MockValueSpace serialization roundtrips through JSON.
        #[test]
        fn mock_value_space_roundtrip(variant in arb_mock_value_space()) {
            let json = serde_json::to_string(&variant).expect("serialize");
            let deserialized: MockValueSpace = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(variant, deserialized);
        }

        /// UnavailableReason serialization roundtrips through JSON.
        #[test]
        fn unavailable_reason_roundtrip(variant in arb_unavailable_reason()) {
            let json = serde_json::to_string(&variant).expect("serialize");
            let deserialized: UnavailableReason = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(variant, deserialized);
        }

        /// classify_live_call always returns Success when there is no error.
        #[test]
        fn no_error_always_success(has_value in any::<bool>()) {
            let value = serde_json::json!(42);
            let value_ref = if has_value { Some(&value) } else { None };
            let result = classify_live_call(value_ref, None);
            prop_assert_eq!(result, LiveCallOutcome::Success);
        }

        /// Any error message containing a known connection failure pattern
        /// is classified as Unavailable (not AppError or Success).
        #[test]
        fn known_pattern_always_unavailable(
            (pattern, _expected_reason) in arb_connection_failure_message(),
            prefix in ".{0,20}",
            suffix in ".{0,20}",
        ) {
            let message = format!("{prefix}{pattern}{suffix}");
            let error = ErrorInfo {
                error_type: "Error".to_string(),
                message,
                stack: None,
                error_category: None,
            };
            let result = classify_live_call(None, Some(&error));
            match result {
                LiveCallOutcome::Unavailable(_) => {} // correct
                other => prop_assert!(false,
                    "expected Unavailable for pattern {:?}, got {:?}", pattern, other),
            }
        }

        /// Errors with infrastructure error types are always classified as Unavailable.
        #[test]
        fn infra_error_type_always_unavailable(
            error_type in prop::sample::select(INFRA_ERROR_TYPES),
            message in ".{0,50}",
        ) {
            let error = ErrorInfo {
                error_type: error_type.to_string(),
                message,
                stack: None,
                error_category: None,
            };
            let result = classify_live_call(None, Some(&error));
            match result {
                LiveCallOutcome::Unavailable(_) => {} // correct
                other => prop_assert!(false,
                    "expected Unavailable for error type {:?}, got {:?}", error_type, other),
            }
        }

        /// classify_live_call never panics on arbitrary error info.
        #[test]
        fn classify_never_panics(
            error_type in ".{0,30}",
            message in ".{0,100}",
            has_stack in any::<bool>(),
            has_category in any::<bool>(),
            has_return in any::<bool>(),
        ) {
            let error = ErrorInfo {
                error_type,
                message,
                stack: if has_stack { Some("stack".to_string()) } else { None },
                error_category: if has_category {
                    Some("infrastructure".to_string())
                } else {
                    None
                },
            };
            let value = serde_json::json!(null);
            let value_ref = if has_return { Some(&value) } else { None };

            // Should not panic
            let _ = classify_live_call(value_ref, Some(&error));
        }

        /// classify_connection_failure is idempotent.
        #[test]
        fn classify_connection_failure_idempotent(
            error_type in ".{0,30}",
            message in ".{0,100}",
        ) {
            let error = ErrorInfo {
                error_type,
                message,
                stack: None,
                error_category: None,
            };
            let r1 = classify_connection_failure(&error);
            let r2 = classify_connection_failure(&error);
            prop_assert_eq!(r1, r2);
        }
    }
}
